/* wif-das-classificationtoteassort-interface-sql-oracle.xml - insertDasAssortResultWave - DAS Assort Result 웨이브 INSERT SQL */
INSERT INTO TWIF_DAS_PRCSRSLT_WA
(
	WASEQ
	,CTKEY
	,OWKEY
	,WAHDKEY
	,DASDIV
	,IFCD
	,WIFIFID
	,IFID
	,IFREQDT
	,IFTYPE
	,IFSRCMODULE
	,IFTGTMODULE
	,IFSTATUS
	,IFERRCD
	,IFERRMSG
	,IFPRCSDATE
	,ORD
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
	,IFRETRYYN
	,IFRETRYIFID
)
VALUES
(
	#{waSeq}
	,#{ctKey}
	,#{owKey}
	,#{waHdKey}
	,#{dasDiv}
	,#{ifCd}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{ifretryyn}
	,#{ifretryifid}
)

/* wif-das-classificationtoteassort-interface-sql-oracle.xml - insertDasAssortResultOrder - DAS Assort Result 오더 INSERT SQL */
